# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorSystem, Props}

class AccountManager extends Actor {
  var balance = 0.0 // volatile or synchronized would introduce overhead, assuming you really know what you're doing with this requirement

  def receive = {
    case Deposit(amount) => balance += amount
    case Withdraw(amount) if (balance >= amount) =>
      balance -= amount
      sender() ! BalanceUpdated(balance)
    case _ => sender() ! "Unknown command"
  }

  override def postStop(): Unit = super.postStop()
}

case class Deposit(amount: Double)

case class Withdraw(amount: Double)

case object BalanceUpdated

object AccountManager {
  val system = ActorSystem("my-system")
  val accountActor = system.actorOf(Props(new AccountManager), name = "account-manager")

  // Test the actor
  def main(args: Array[String]): Unit = {
    accountActor ! Deposit(100.0)
    Thread.sleep(10) // Introduce a delay to simulate concurrent access
    accountActor ! Withdraw(50.0)
    Thread.sleep(10) // Wait for result
    println(accountActor ? BalanceUpdated) // Should print 50.0
  }
}